<script>
document.addEventListener('DOMContentLoaded',()=>{lucide.createIcons();});
window.addEventListener('scroll',()=>{
  document.getElementById('topnav').classList.toggle('scrolled',window.scrollY>40);
});
function scrollToLogin(){
  document.getElementById('login-section').scrollIntoView({behavior:'smooth',block:'center'});
}
function switchTab(t){
  document.querySelectorAll('.auth-tab').forEach((b,i)=>{
    b.classList.toggle('active',(i===0&&t==='login')||(i===1&&t==='register'));
  });
  document.getElementById('sec-login').classList.toggle('active',t==='login');
  document.getElementById('sec-register').classList.toggle('active',t==='register');
}
function pwStrength(v){
  const f=document.getElementById('pwf');if(!f)return;
  let s=0;
  if(v.length>=8)s++;if(v.length>=12)s++;
  if(/[A-Z]/.test(v))s++;if(/[0-9]/.test(v))s++;if(/[^A-Za-z0-9]/.test(v))s++;
  const l=[['0%','transparent'],['25%','#ef4444'],['50%','#f59e0b'],['75%','#3b82f6'],['90%','#16a34a'],['100%','#059669']];
  f.style.width=l[Math.min(s,5)][0];f.style.background=l[Math.min(s,5)][1];
}
const obs=new IntersectionObserver(entries=>{
  entries.forEach(e=>{if(e.isIntersecting)e.target.classList.add('visible');});
},{threshold:0.1});
document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));


(function () {
  const facultyMap = <?= json_encode(FULAFIA_FACULTIES, JSON_UNESCAPED_UNICODE) ?>;
  const facultySelect     = document.getElementById('reg_faculty');
  const departmentSelect  = document.getElementById('reg_department');

  facultySelect.addEventListener('change', function () {
    const chosen = this.value;
    departmentSelect.innerHTML = '';
    departmentSelect.disabled = true;

    if (!chosen || !facultyMap[chosen]) {
      departmentSelect.innerHTML = '<option value="">— Select Faculty first —</option>';
      return;
    }

    const placeholder = document.createElement('option');
    placeholder.value = '';
    placeholder.textContent = '— Select Department —';
    departmentSelect.appendChild(placeholder);

    facultyMap[chosen].forEach(function (dept) {
      const opt = document.createElement('option');
      opt.value = dept;
      opt.textContent = dept;
      departmentSelect.appendChild(opt);
    });

    departmentSelect.disabled = false;
  });
})();
</script>
</body>
</html>